function normalize(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function tokenise(value) {
  return normalize(value).split(/\s+/).filter((token) => token.length > 1);
}

function overlapCount(a, b) {
  const bSet = new Set(b);
  return a.filter((token) => bSet.has(token)).length;
}

function linkedInSlugTokens(link) {
  try {
    const url = new URL(link);
    const match = url.pathname.match(/\/company\/([^/?#]+)/i);
    if (!match) return [];
    return tokenise(match[1].replace(/-/g, ' '));
  } catch {
    return [];
  }
}

function canonicalLinkedIn(link) {
  try {
    const url = new URL(link);
    const match = url.pathname.match(/(\/company\/[^/?#]+)/i);
    return match ? `${url.origin}${match[1]}/` : link;
  } catch {
    return link;
  }
}

const results = Array.isArray($json.organic) ? $json.organic : [];
const homepageName = String($('Parse Parent Company').item.json.company_homepage_name || '').trim();
const parentCompany = String($('Parse Parent Company').item.json.parent_company || '').trim();
const homepageNorm = normalize(homepageName);
const parentNorm = normalize(parentCompany);
const homepageTokens = tokenise(homepageName);
const parentTokens = tokenise(parentCompany);

let best = { score: 0, link: '' };

for (const result of results) {
  const link = String(result.link || '').trim();
  if (!/linkedin\.com\/company\//i.test(link)) continue;

  const haystack = normalize(`${result.title || ''} ${result.snippet || ''}`);
  const slugTokens = linkedInSlugTokens(link);
  let score = 0;

  if (homepageNorm && haystack.includes(homepageNorm)) score += 5;
  if (parentNorm && parentNorm !== homepageNorm && haystack.includes(parentNorm)) score += 4;

  const homepageOverlap = overlapCount(homepageTokens, slugTokens);
  const parentOverlap = overlapCount(parentTokens, slugTokens);

  if (homepageOverlap >= Math.min(2, homepageTokens.length || 0) && homepageOverlap > 0) score += 3;
  else if (homepageOverlap > 0) score += 1;

  if (parentNorm && parentNorm !== homepageNorm) {
    if (parentOverlap >= Math.min(2, parentTokens.length || 0) && parentOverlap > 0) score += 2;
    else if (parentOverlap > 0) score += 1;
  }

  if (score > best.score) {
    best = { score, link: canonicalLinkedIn(link) };
  }
}

return [{ json: { company_linkedin_url: best.score >= 4 ? best.link : '' } }];

function toHomepageUrl(value) {
  const raw = String(value || '').trim();
  if (!raw) return '';
  try {
    const url = raw.startsWith('http') ? new URL(raw) : new URL(`https://${raw}`);
    return `${url.protocol}//${url.hostname}/`;
  } catch {
    return raw;
  }
}

